var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"아우드라...? 그게 누구이옵니까?","JPN":"アウドラ……？　それは誰のことでしょうか？","ENG":"Audra...? Who is that?","TWN":"奧德拉……？那是誰？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"뭐?","JPN":"え？","ENG":"What?","TWN":"怎樣？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"넌 모르는 거야? 저 여자에 대해서?","JPN":"知らないの？　あの女のこと。","ENG":"You don't know? Who she is?","TWN":"你不認識她？有關她的一切？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"...예.","JPN":"……はい。","ENG":"...No.","TWN":"……是。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"모르는 게 당연해요.","JPN":"知らなくて当然です。","ENG":"It's only natural you wouldn't know.","TWN":"不知道也很正常。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"전 지금껏 누구의 눈에도 띄지 않고 지내왔거든요.","JPN":"今まで誰の目にも触れずに過ごしてきましたから。","ENG":"I've lived all this time without ever drawing anyone's notice.","TWN":"我一直都生活在不引人注意的地方。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"누구의 눈에도 띄지 않다니... 낙원에선 누구도 숨을 필요 없습니다.","JPN":"誰の目にも触れないだなんて……楽園では誰も隠れる必要などありません。","ENG":"Without drawing anyone's notice... In the Promised Land, no one has any need to hide.","TWN":"不引人注意……在樂園裡，不需要躲避任何人。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"부디 제 손을 잡으소서.","JPN":"どうかわたくしの手をお取りください。","ENG":"Please, take my hand.","TWN":"請握住我的手。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"당신은 변함없이 좋은 분이네요, 예하.","JPN":"あなたは相変わらず優しい方ですね、猊下。","ENG":"You are as kind as ever, Your Eminence.","TWN":"你依舊是個好人呢，主教。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"...예하?","JPN":"……猊下？","ENG":"...Your Eminence?","TWN":"……主教？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"물러서, 에클레시아!","JPN":"下がって、エクレシア！","ENG":"Step back, Ecclesia!","TWN":"退後，艾可露西亞！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"위험해. 저 녀석이 타기리온이라고!","JPN":"危ない。あいつがタギリオンなんだよ！","ENG":"She's dangerous. She is Thagirion!","TWN":"危險，那傢伙就是塔基里翁！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"저 소녀가 마왕...?","JPN":"あの少女が魔王……？","ENG":"That girl is a Demon Lord...?","TWN":"那個少女是魔王……？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"하지만, 제가 들었던 모습과는 너무 다르온데...","JPN":"ですが、わたくしが聞いていた姿とはかけ離れております……","ENG":"But she looks nothing like what I had heard...","TWN":"可是她看起來和我聽說的完全不同……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"겉모습에 속아선 안돼. 우릴 기만하려는 거야.","JPN":"外見に騙されちゃダメ。私たちを欺こうとしてるんだ。","ENG":"Don't be fooled by appearances. She's trying to deceive us.","TWN":"別被外表騙了，她只是想騙過我們。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"목적을 밝혀!","JPN":"何が目的だ！","ENG":"State your purpose!","TWN":"說出你的目的！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"날 왜 여기로 데려왔는지. 이 낙원이라는 곳은 대체 뭔지!","JPN":"どうして私をここに連れてきたのか、この楽園という場所はいったい何なのか！","ENG":"Why did you bring me here? And what exactly is this place called the Promised Land?!","TWN":"為什麼把我帶到這裡，這個樂園到底是什麼地方！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"타기리온은 이곳에 없으니 걱정 마세요.","JPN":"タギリオンはここにいません。心配しないでください。","ENG":"Thagirion is not here, so there's no need to worry.","TWN":"塔基里翁不在這裡，你不用擔心。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그녀의 숨이 붙어있는 한, 낙원에 발 들이지 않기로... 함께 약속했거든요.","JPN":"彼女が生きている限り、楽園に足を踏み入れないことを……一緒に約束しましたから。","ENG":"As long as she still draws breath, she promised... never to set foot in the Promised Land.","TWN":"我們曾約定……只要她還活著，就不會踏入樂園一步。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"뭐...?","JPN":"は……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그게 무슨 소리지? 그 모습을 하고 있다 해서, 네가 타기리온과 다른 존재라도 된다는 거야?","JPN":"どういうこと？　その姿をしてるからって、君がタギリオンとは違う存在だとでも言いたいの？","ENG":"What is that supposed to mean? Just because you look like that, are you saying you're somehow a different being from Thagirion?","TWN":"你在說什麼？難道你的意思是就算你長這樣，也不是塔基里翁？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"맞아요.","JPN":"そのとおりです。","ENG":"That's right.","TWN":"沒錯。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"타기리온이 마왕이 되기 위해 먼저 했던 일은... 가장 나약한 부분을 도려내는 일이었거든요.","JPN":"タギリオンが魔王になるために最初にやったことは……一番弱い部分をえぐり出すことでしたから。","ENG":"The first thing Thagirion did to become a Demon Lord... was cut away the weakest part of herself.","TWN":"塔基里翁為了成為魔王最先做的事……就是切除自己最軟弱的部分。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"가장... 나약한 부분이라고?","JPN":"一番……弱い部分？","ENG":"The weakest... part?","TWN":"最……軟弱的部分？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"저는 마왕이 되지 못한 그녀의 일부. 그녀가 두고 떠난 마음이에요.","JPN":"私は魔王になれなかった彼女の一部。彼女が置き去りにした心です。","ENG":"I am the part of her that could not become a Demon Lord. The heart she left behind.","TWN":"我是她沒能成為魔王的那一部分，我是她留下的心。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"사람을 잡아먹는 괴물에게 사람의 마음 같은 건 필요 없으니까.","JPN":"人を食らう化け物に、人の心なんて要りませんから。","ENG":"A monster that devours people has no need for a human heart.","TWN":"因為吞噬人類的怪物，不需要人類的心臟。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"당신이... 마왕 타기리온의 마음...?","JPN":"あなたが……魔王タギリオンの心……？","ENG":"You're... the heart of Demon Lord Thagirion...?","TWN":"你是……魔王塔基里翁的心？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"소녀는 본래 마왕이 될 운명이었어요.","JPN":"少女は最初から魔王になる運命でした。","ENG":"The girl was originally fated to become a Demon Lord.","TWN":"那個少女本來就注定會成為魔王。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그걸 거스르려다가... 너무 많은 희생을 불러왔죠.","JPN":"それに抵抗しようとして……あまりにも多くの犠牲を引き起こしました。","ENG":"In trying to defy that... she brought about far too many sacrifices.","TWN":"她試圖違抗命運……結果導致太多犧牲。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"우린 지금 그 대가를 치르고 있는 거에요.","JPN":"私たちは今まさに、その代償を払っているところなのです。","ENG":"And now we are paying the price for it.","TWN":"而我們現在正在承受那份代價。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"대가를 치른다니?","JPN":"代償を払うって？","ENG":"Paying the price?","TWN":"承受代價？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"타기리온은 지금도 멀쩡히 사람들을 유린하며 세계를 파괴하고 있어!","JPN":"タギリオンは今も人々を踏みにじりながら世界を破壊しているんだよ！","ENG":"Thagirion is still trampling people and destroying worlds without a care!","TWN":"塔基里翁現在仍在踐踏人類、破壞世界！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};